// // This module controls the output voltage of a linear voltage regulator. When the enable signal is high, the output voltage is set to the reference voltage. Otherwise, it is set to ground.
module voltage_regulator (
    input wire enable,
    input wire [7:0] reference_voltage,
    output wire [7:0] output_voltage
);
    assign output_voltage = enable ? reference_voltage : 8'b00000000;
endmodule
